@page "/apply"
@rendermode InteractiveServer
@using sv_acfb342491db426fba8e112a4f9c2708.Models
@using sv_acfb342491db426fba8e112a4f9c2708.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="card mt-4">
        <div class="card-body">
            @if (submitted)
            {
                <div class="text-center py-5">
                    <div class="mb-3">
                        <span style="font-size: 3rem; color: #198754;">&#10004;</span>
                    </div>
                    <h3 class="text-success">Application Submitted!</h3>
                    <p class="lead mt-3">Your application ID is <strong>#@applicationId</strong></p>
                    <p class="text-muted">We'll be in touch soon.</p>
                </div>
            }
            else
            {
                @switch (currentStep)
                {
                    case 1:
                        <StepPersonalInfo FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                          EmailError="@emailError" ValidationErrors="@validationErrors"
                                          OnFullNameChanged="v => fullName = v"
                                          OnEmailChanged="v => email = v"
                                          OnPhoneChanged="v => phone = v"
                                          OnAddressChanged="v => address = v"
                                          OnNext="NextFromPersonalInfo" IsValidating="@isValidating" />
                        break;
                    case 2:
                        <StepWorkHistory Entries="@workEntries"
                                         ValidationErrors="@validationErrors"
                                         OnBack="Back" OnNext="NextFromWorkHistory" />
                        break;
                    case 3:
                        <StepReferences References="@references"
                                        ValidationErrors="@validationErrors"
                                        OnBack="Back" OnNext="NextFromReferences" />
                        break;
                    case 4:
                        <StepCoverLetter CoverLetter="@coverLetter"
                                         OnCoverLetterChanged="v => coverLetter = v"
                                         ValidationErrors="@validationErrors"
                                         OnBack="Back" OnNext="NextFromCoverLetter" />
                        break;
                    case 5:
                        <StepReview FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                    WorkEntries="@workEntries" References="@references" CoverLetter="@coverLetter"
                                    OnEditStep="GoToStep" OnSubmit="Submit" IsSubmitting="@isSubmitting"
                                    OnBack="Back" />
                        break;
                }
            }
        </div>
    </div>
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private List<string> validationErrors = new();
    private string emailError = string.Empty;
    private bool isValidating;
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = string.Empty;

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            currentStep = step;
            validationErrors.Clear();
            emailError = string.Empty;
        }
    }

    private void Back()
    {
        if (currentStep > 1)
        {
            currentStep--;
            validationErrors.Clear();
            emailError = string.Empty;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        validationErrors.Clear();
        emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(fullName)) validationErrors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(email)) validationErrors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(phone)) validationErrors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(address)) validationErrors.Add("Address is required.");

        if (validationErrors.Count > 0) return;

        isValidating = true;
        StateHasChanged();

        var isValidEmail = await ApplicationService.ValidateEmailAsync(email);
        isValidating = false;

        if (!isValidEmail)
        {
            emailError = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void NextFromWorkHistory()
    {
        validationErrors.Clear();
        foreach (var (entry, i) in workEntries.Select((e, i) => (e, i)))
        {
            if (string.IsNullOrWhiteSpace(entry.Company))
                validationErrors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                validationErrors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate == default)
                validationErrors.Add($"Position {i + 1}: Start date is required.");
        }
        if (validationErrors.Count > 0) return;

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void NextFromReferences()
    {
        validationErrors.Clear();
        foreach (var (r, i) in references.Select((r, i) => (r, i)))
        {
            if (string.IsNullOrWhiteSpace(r.Name))
                validationErrors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                validationErrors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                validationErrors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                validationErrors.Add($"Reference {i + 1}: Phone is required.");
        }
        if (validationErrors.Count > 0) return;

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void NextFromCoverLetter()
    {
        validationErrors.Clear();
        if (string.IsNullOrWhiteSpace(coverLetter))
            validationErrors.Add("Cover letter is required.");
        if (coverLetter.Length > 2000)
            validationErrors.Add("Cover letter must be 2000 characters or fewer.");
        if (validationErrors.Count > 0) return;

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task Submit()
    {
        isSubmitting = true;
        StateHasChanged();

        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate,
                    e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitting = false;
        submitted = true;
        completedSteps.Add(5);
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>Work History</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in ValidationErrors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < Entries.Count; idx++)
{
    var i = idx;
    var entry = Entries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(i + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @oninput="e => entry.Company = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @oninput="e => entry.Title = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="row mb-3">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value)" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value)" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@i" checked="@entry.IsCurrent"
                               @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                        <label class="form-check-label" for="current-@i">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@entry.Description"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? string.Empty"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private static string FormatDate(DateTime date) =>
        date == default ? string.Empty : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? string.Empty;

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}

@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>References</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in ValidationErrors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var reference = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(i + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(i)">Remove</button>
                }
            </div>

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @oninput="e => reference.Name = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @oninput="e => reference.Relationship = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @oninput="e => reference.Email = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @oninput="e => reference.Phone = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference()
    {
        if (References.Count < 3) References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2) References.RemoveAt(index);
    }
}

@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>Review & Submit</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (entry, i) in WorkEntries.Select((e, i) => (e, i)))
        {
            @if (i > 0) { <hr /> }
            <h6>@entry.Title at @entry.Company</h6>
            <p class="text-muted mb-1">
                @entry.StartDate.ToString("MMM yyyy") &ndash;
                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
            </p>
            @if (!string.IsNullOrWhiteSpace(entry.Description))
            {
                <p class="mb-0">@entry.Description</p>
            }
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (reference, i) in References.Select((r, i) => (r, i)))
        {
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@reference.Name</dd>
                <dt class="col-sm-3">Relationship</dt><dd class="col-sm-9">@reference.Relationship</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@reference.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@reference.Phone</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Submitting...</text>
        }
        else
        {
            <text>Submit Application</text>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = string.Empty;
    [Parameter] public string Email { get; set; } = string.Empty;
    [Parameter] public string Phone { get; set; } = string.Empty;
    [Parameter] public string Address { get; set; } = string.Empty;
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = string.Empty;
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}

