{"file_text": "<div class="d-flex justify-content-between align-items-center mb-2 step-indicator">
    @for (int i = 1; i <= stepNames.Length; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isFuture = !isCurrent && !isCompleted;

        <div class="text-center flex-fill position-relative">
            @if (step > 1)
            {
                <div class="step-connector @(CompletedSteps.Contains(step - 1) ? "completed" : "")"></div>
            }
            <button class="btn rounded-circle step-circle @(isCurrent ? "btn-primary" : isCompleted ? "btn-success" : "btn-secondary opacity-50")"
                    style="width: 36px; height: 36px; font-size: 0.85rem; padding: 0;"
                    disabled="@(isFuture)"
                    @onclick="() => OnStepClicked.InvokeAsync(step)">
                @if (isCompleted && !isCurrent)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    @step
                }
            </button>
            <div class="small mt-1 @(isFuture ? "text-muted" : "") @(isCurrent ? "fw-bold" : "")">
                @stepNames[step - 1]
            </div>
        </div>
    }
</div>

<style>
    .step-indicator .step-connector {
        position: absolute;
        top: 18px;
        left: -50%;
        right: 50%;
        height: 2px;
        background-color: #dee2e6;
        z-index: 0;
    }
    .step-indicator .step-connector.completed {
        background-color: #198754;
    }
    .step-indicator .step-circle {
        position: relative;
        z-index: 1;
    }
</style>

