<h4>Work History</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in ValidationErrors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < Entries.Count; idx++)
{
    var i = idx;
    var entry = Entries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(i + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @oninput="e => entry.Company = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @oninput="e => entry.Title = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="row mb-3">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value)" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value)" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@i" checked="@entry.IsCurrent"
                               @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                        <label class="form-check-label" for="current-@i">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@entry.Description"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? string.Empty"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private static string FormatDate(DateTime date) =>
        date == default ? string.Empty : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? string.Empty;

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}
