@page "/apply"
@rendermode InteractiveServer
@using sv_acfb342491db426fba8e112a4f9c2708.Models
@using sv_acfb342491db426fba8e112a4f9c2708.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="card mt-4">
        <div class="card-body">
            @if (submitted)
            {
                <div class="text-center py-5">
                    <div class="mb-3">
                        <span style="font-size: 3rem; color: #198754;">&#10004;</span>
                    </div>
                    <h3 class="text-success">Application Submitted!</h3>
                    <p class="lead mt-3">Your application ID is <strong>#@applicationId</strong></p>
                    <p class="text-muted">We'll be in touch soon.</p>
                </div>
            }
            else
            {
                @switch (currentStep)
                {
                    case 1:
                        <StepPersonalInfo FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                          EmailError="@emailError" ValidationErrors="@validationErrors"
                                          OnFullNameChanged="v => fullName = v"
                                          OnEmailChanged="v => email = v"
                                          OnPhoneChanged="v => phone = v"
                                          OnAddressChanged="v => address = v"
                                          OnNext="NextFromPersonalInfo" IsValidating="@isValidating" />
                        break;
                    case 2:
                        <StepWorkHistory Entries="@workEntries"
                                         ValidationErrors="@validationErrors"
                                         OnBack="Back" OnNext="NextFromWorkHistory" />
                        break;
                    case 3:
                        <StepReferences References="@references"
                                        ValidationErrors="@validationErrors"
                                        OnBack="Back" OnNext="NextFromReferences" />
                        break;
                    case 4:
                        <StepCoverLetter CoverLetter="@coverLetter"
                                         OnCoverLetterChanged="v => coverLetter = v"
                                         ValidationErrors="@validationErrors"
                                         OnBack="Back" OnNext="NextFromCoverLetter" />
                        break;
                    case 5:
                        <StepReview FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                    WorkEntries="@workEntries" References="@references" CoverLetter="@coverLetter"
                                    OnEditStep="GoToStep" OnSubmit="Submit" IsSubmitting="@isSubmitting"
                                    OnBack="Back" />
                        break;
                }
            }
        </div>
    </div>
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private List<string> validationErrors = new();
    private string emailError = string.Empty;
    private bool isValidating;
    private bool isSubmitting;
    private bool submitted;
    private int applicationId;

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = string.Empty;

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
        {
            currentStep = step;
            validationErrors.Clear();
            emailError = string.Empty;
        }
    }

    private void Back()
    {
        if (currentStep > 1)
        {
            currentStep--;
            validationErrors.Clear();
            emailError = string.Empty;
        }
    }

    private async Task NextFromPersonalInfo()
    {
        validationErrors.Clear();
        emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(fullName)) validationErrors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(email)) validationErrors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(phone)) validationErrors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(address)) validationErrors.Add("Address is required.");

        if (validationErrors.Count > 0) return;

        isValidating = true;
        StateHasChanged();

        var isValidEmail = await ApplicationService.ValidateEmailAsync(email);
        isValidating = false;

        if (!isValidEmail)
        {
            emailError = "Please enter a valid email address.";
            return;
        }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void NextFromWorkHistory()
    {
        validationErrors.Clear();
        foreach (var (entry, i) in workEntries.Select((e, i) => (e, i)))
        {
            if (string.IsNullOrWhiteSpace(entry.Company))
                validationErrors.Add($"Position {i + 1}: Company name is required.");
            if (string.IsNullOrWhiteSpace(entry.Title))
                validationErrors.Add($"Position {i + 1}: Job title is required.");
            if (entry.StartDate == default)
                validationErrors.Add($"Position {i + 1}: Start date is required.");
        }
        if (validationErrors.Count > 0) return;

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void NextFromReferences()
    {
        validationErrors.Clear();
        foreach (var (r, i) in references.Select((r, i) => (r, i)))
        {
            if (string.IsNullOrWhiteSpace(r.Name))
                validationErrors.Add($"Reference {i + 1}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship))
                validationErrors.Add($"Reference {i + 1}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email))
                validationErrors.Add($"Reference {i + 1}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone))
                validationErrors.Add($"Reference {i + 1}: Phone is required.");
        }
        if (validationErrors.Count > 0) return;

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void NextFromCoverLetter()
    {
        validationErrors.Clear();
        if (string.IsNullOrWhiteSpace(coverLetter))
            validationErrors.Add("Cover letter is required.");
        if (coverLetter.Length > 2000)
            validationErrors.Add("Cover letter must be 2000 characters or fewer.");
        if (validationErrors.Count > 0) return;

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task Submit()
    {
        isSubmitting = true;
        StateHasChanged();

        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate,
                    e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitting = false;
        submitted = true;
        completedSteps.Add(5);
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

