@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>Work History</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in ValidationErrors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < Entries.Count; idx++)
{
    var i = idx;
    var entry = Entries[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(i + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveEntry(i)">Remove</button>
                }
            </div>

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Company"
                           @oninput="e => entry.Company = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@entry.Title"
                           @oninput="e => entry.Title = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="row mb-3">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
                           @onchange="e => entry.StartDate = ParseDate(e.Value)" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
                           disabled="@entry.IsCurrent"
                           @onchange="e => entry.EndDate = ParseNullableDate(e.Value)" />
                </div>
                <div class="col-md-4 d-flex align-items-end mb-1">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@i" checked="@entry.IsCurrent"
                               @onchange="e => { entry.IsCurrent = (bool)(e.Value ?? false); if (entry.IsCurrent) entry.EndDate = null; }" />
                        <label class="form-check-label" for="current-@i">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@entry.Description"
                          @oninput="e => entry.Description = e.Value?.ToString() ?? string.Empty"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1) Entries.RemoveAt(index);
    }

    private static string FormatDate(DateTime date) =>
        date == default ? string.Empty : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? string.Empty;

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;
}

@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>References</h4>

@if (ValidationErrors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in ValidationErrors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int idx = 0; idx < References.Count; idx++)
{
    var i = idx;
    var reference = References[i];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(i + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(i)">Remove</button>
                }
            </div>

            <div class="row mb-3">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Name"
                           @oninput="e => reference.Name = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" value="@reference.Relationship"
                           @oninput="e => reference.Relationship = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" value="@reference.Email"
                           @oninput="e => reference.Email = e.Value?.ToString() ?? string.Empty" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control" value="@reference.Phone"
                           @oninput="e => reference.Phone = e.Value?.ToString() ?? string.Empty" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary btn-sm mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public List<string> ValidationErrors { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference()
    {
        if (References.Count < 3) References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2) References.RemoveAt(index);
    }
}

@using static sv_acfb342491db426fba8e112a4f9c2708.Components.Pages.Apply.Apply

<h4>Review & Submit</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(1)'>Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(2)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (entry, i) in WorkEntries.Select((e, i) => (e, i)))
        {
            @if (i > 0) { <hr /> }
            <h6>@entry.Title at @entry.Company</h6>
            <p class="text-muted mb-1">
                @entry.StartDate.ToString("MMM yyyy") &ndash;
                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
            </p>
            @if (!string.IsNullOrWhiteSpace(entry.Description))
            {
                <p class="mb-0">@entry.Description</p>
            }
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(3)'>Edit</button>
    </div>
    <div class="card-body">
        @foreach (var (reference, i) in References.Select((r, i) => (r, i)))
        {
            @if (i > 0) { <hr /> }
            <dl class="row mb-0">
                <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@reference.Name</dd>
                <dt class="col-sm-3">Relationship</dt><dd class="col-sm-9">@reference.Relationship</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@reference.Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@reference.Phone</dd>
            </dl>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-sm btn-link" @onclick='() => OnEditStep.InvokeAsync(4)'>Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Submitting...</text>
        }
        else
        {
            <text>Submit Application</text>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = string.Empty;
    [Parameter] public string Email { get; set; } = string.Empty;
    [Parameter] public string Phone { get; set; } = string.Empty;
    [Parameter] public string Address { get; set; } = string.Empty;
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = string.Empty;
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
}
